# Assuming the original constants are defined somewhere in the codebase
PROJECT_MEMBER_ROLE = {
    'ADMIN': 'admin',
    'MEMBER': 'member',
    'GUEST': 'guest'
}

# Updated DTOs with correct role validation
class ProjectMemberDTO:
    def __init__(self, role):
        self.role = role
        self.validate_role()

    def validate_role(self):
        if self.role not in PROJECT_MEMBER_ROLE.values():
            raise ValueError(f"Invalid role: {self.role}. Must be one of {list(PROJECT_MEMBER_ROLE.values())}")

# Minimal unit tests for critical behaviors
import unittest

class TestProjectMemberDTO(unittest.TestCase):
    def test_valid_role_admin(self):
        dto = ProjectMemberDTO('admin')
        self.assertEqual(dto.role, 'admin')

    def test_valid_role_member(self):
        dto = ProjectMemberDTO('member')
        self.assertEqual(dto.role, 'member')

    def test_valid_role_guest(self):
        dto = ProjectMemberDTO('guest')
        self.assertEqual(dto.role, 'guest')

    def test_invalid_role(self):
        with self.assertRaises(ValueError):
            ProjectMemberDTO('invalid_role')

    def test_edge_case_empty_role(self):
        with self.assertRaises(ValueError):
            ProjectMemberDTO('')

    def test_edge_case_none_role(self):
        with self.assertRaises(ValueError):
            ProjectMemberDTO(None)

if __name__ == '__main__':
    unittest.main()
